/**
 * SSP (Server Side Proxy) admin tab interactions.
 *
 * Handles activate, enable/disable toggle, disconnect,
 * sync, test connection, and proxy failure behavior setting.
 *
 * @since 1.57.0
 */

jQuery(function ($) {

	const $activateBtn    = $("#pmw-ssp-activate-btn")
	const $reactivateBtn  = $("#pmw-ssp-reactivate-btn")
	const $disableBtn     = $("#pmw-ssp-disable-btn")
	const $disconnectBtn  = $("#pmw-ssp-disconnect-btn")
	const $syncBtn        = $("#pmw-ssp-sync-btn")
	const $testBtn        = $("#pmw-ssp-test-btn")
	const $tokenInput     = $("#pmw-ssp-sync-token")
	const $failureBehavior = $("#pmw-ssp-failure-behavior")

	// If no SSP elements exist on the page, bail early
	if (!$activateBtn.length && !$syncBtn.length) return

	const showStatus = ($el, message, type) => {
		const className = type === "success"
			? "pmw-ssp-msg-success"
			: type === "error"
				? "pmw-ssp-msg-error"
				: "pmw-ssp-msg-loading"

		$el.html(`<span class="${className}">${message}</span>`)
	}

	const clearStatus = ($el) => {
		$el.html("")
	}

	const apiCall = (endpoint, method, body) => {
		const opts = {
			method,
			credentials: "same-origin",
			headers: {
				"Content-Type": "application/json",
				"X-WP-Nonce": pmwAdminApi.nonce,
			},
		}

		if (body) {
			opts.body = JSON.stringify(body)
		}

		return fetch(pmwAdminApi.root + "pmw/v1/ssp/" + endpoint, opts)
			.then(response => response.json())
	}

	// ─── Activate ──────────────────────────────────────────

	$activateBtn.on("click", function () {
		const token = $.trim($tokenInput.val())

		if (!token) {
			showStatus($("#pmw-ssp-activate-status"), "Please enter a sync token.", "error")
			return
		}

		// Basic hex validation
		if (!/^[a-f0-9]{32,64}$/i.test(token)) {
			showStatus($("#pmw-ssp-activate-status"), "Invalid token format. Expected a hex string (32-64 characters).", "error")
			return
		}

		$activateBtn.prop("disabled", true).text("Activating…")
		clearStatus($("#pmw-ssp-activate-status"))

		apiCall("activate", "POST", { sync_token: token })
			.then(data => {
				if (data.success) {
					showStatus($("#pmw-ssp-activate-status"), "✓ SSP activated successfully. Reloading…", "success")
					setTimeout(() => window.location.reload(), 1500)
				} else {
					const msg = data.message || data.data?.message || "Activation failed."
					showStatus($("#pmw-ssp-activate-status"), msg, "error")
					$activateBtn.prop("disabled", false).text("Activate")
				}
			})
			.catch(err => {
				showStatus($("#pmw-ssp-activate-status"), "Network error: " + err.message, "error")
				$activateBtn.prop("disabled", false).text("Activate")
			})
	})

	// ─── Enable / Disable Buttons ─────────────────────────

	$reactivateBtn.on("click", function () {
		$reactivateBtn.prop("disabled", true).text("Re-activating…")
		showStatus($("#pmw-ssp-toggle-status"), "Re-activating…", "loading")

		apiCall("enable", "POST")
			.then(data => {
				if (data.success) {
					showStatus($("#pmw-ssp-toggle-status"), "✓ " + data.message + " Reloading…", "success")
					setTimeout(() => window.location.reload(), 1500)
				} else {
					const msg = data.message || data.data?.message || "Re-activation failed."
					showStatus($("#pmw-ssp-toggle-status"), msg, "error")
					$reactivateBtn.prop("disabled", false).text("Re-activate")
				}
			})
			.catch(err => {
				showStatus($("#pmw-ssp-toggle-status"), "Network error: " + err.message, "error")
				$reactivateBtn.prop("disabled", false).text("Re-activate")
			})
	})

	$disableBtn.on("click", function () {
		$disableBtn.prop("disabled", true).text("Disabling…")
		showStatus($("#pmw-ssp-toggle-status"), "Disabling…", "loading")

		apiCall("disable", "POST")
			.then(data => {
				if (data.success) {
					showStatus($("#pmw-ssp-toggle-status"), "✓ " + data.message + " Reloading…", "success")
					setTimeout(() => window.location.reload(), 1500)
				} else {
					const msg = data.message || data.data?.message || "Disable failed."
					showStatus($("#pmw-ssp-toggle-status"), msg, "error")
					$disableBtn.prop("disabled", false).text("Disable")
				}
			})
			.catch(err => {
				showStatus($("#pmw-ssp-toggle-status"), "Network error: " + err.message, "error")
				$disableBtn.prop("disabled", false).text("Disable")
			})
	})

	// ─── Disconnect ────────────────────────────────────────

	$disconnectBtn.on("click", function () {
		if (!confirm(
			"Disconnect from SSP?\n\n" +
			"This will permanently delete the sync token and remove all connection data. " +
			"You will need to re-enter the token from the SSP portal to reconnect.\n\n" +
			"Continue?"
		)) {
			return
		}

		$disconnectBtn.prop("disabled", true).text("Disconnecting…")

		apiCall("disconnect", "POST")
			.then(data => {
				if (data.success) {
					showStatus($("#pmw-ssp-disconnect-status"), "SSP disconnected. Reloading…", "success")
					setTimeout(() => window.location.reload(), 1500)
				} else {
					showStatus($("#pmw-ssp-disconnect-status"), data.message || "Disconnect failed.", "error")
					$disconnectBtn.prop("disabled", false).text("Disconnect")
				}
			})
			.catch(err => {
				showStatus($("#pmw-ssp-disconnect-status"), "Network error: " + err.message, "error")
				$disconnectBtn.prop("disabled", false).text("Disconnect")
			})
	})

	// ─── Proxy Failure Behavior ────────────────────────────

	$failureBehavior.on("change", function () {
		const value = $(this).val()

		showStatus($("#pmw-ssp-failure-behavior-status"), "Saving…", "loading")

		apiCall("save-setting", "POST", { key: "proxy_failure_behavior", value })
			.then(data => {
				if (data.success) {
					showStatus($("#pmw-ssp-failure-behavior-status"), "✓ Saved", "success")
					setTimeout(() => clearStatus($("#pmw-ssp-failure-behavior-status")), 3000)
				} else {
					showStatus($("#pmw-ssp-failure-behavior-status"), data.message || "Save failed.", "error")
				}
			})
			.catch(err => {
				showStatus($("#pmw-ssp-failure-behavior-status"), "Network error: " + err.message, "error")
			})
	})

	/**
	 * Update plan and usage status fields from a sync response.
	 */
	const updateSyncMeta = (status) => {
		if (!status) return

		if (status.last_sync_at_formatted) {
			$("#pmw-ssp-last-sync").text(status.last_sync_at_formatted)
		}

		if (status.plan_name) {
			let planHtml = status.plan_name
			if (status.subscription_status && status.subscription_status !== "active") {
				planHtml += ` <span class="pmw-ssp-badge pmw-ssp-badge--inactive">${status.subscription_status.charAt(0).toUpperCase() + status.subscription_status.slice(1)}</span>`
			}
			$("#pmw-ssp-plan-name").html(planHtml)
		}

		if (typeof status.monthly_request_limit !== "undefined" && status.monthly_request_limit > 0) {
			const fmt = (n) => n.toLocaleString()
			$("#pmw-ssp-usage").text(
				`${fmt(status.billable_this_period)} / ${fmt(status.monthly_request_limit)} events (${status.usage_percent}%)`
			)
		}
	}

	// ─── Sync Now ──────────────────────────────────────────

	$syncBtn.on("click", function () {
		$syncBtn.prop("disabled", true).text("Syncing…")
		showStatus($("#pmw-ssp-action-status"), "Pushing configuration…", "loading")

		apiCall("sync", "POST")
			.then(data => {
				if (data.success) {
					showStatus($("#pmw-ssp-action-status"), "✓ Config synced successfully. Reloading…", "success")
					updateSyncMeta(data.status)
					setTimeout(() => window.location.reload(), 1500)
				} else {
					showStatus($("#pmw-ssp-action-status"), data.message || data.data?.message || "Sync failed.", "error")
					$syncBtn.prop("disabled", false).text("Sync Now")
				}
			})
			.catch(err => {
				showStatus($("#pmw-ssp-action-status"), "Network error: " + err.message, "error")
				$syncBtn.prop("disabled", false).text("Sync Now")
			})
	})

	// ─── Test Connection ───────────────────────────────────

	$testBtn.on("click", function () {
		$testBtn.prop("disabled", true).text("Testing…")
		showStatus($("#pmw-ssp-action-status"), "Testing proxy connectivity…", "loading")

		apiCall("test", "POST")
			.then(data => {
				if (data.success) {
					showStatus($("#pmw-ssp-action-status"), "✓ " + data.message, "success")
				} else {
					showStatus($("#pmw-ssp-action-status"), data.message || "Connection test failed.", "error")
				}
				$testBtn.prop("disabled", false).text("Test Connection")
			})
			.catch(err => {
				showStatus($("#pmw-ssp-action-status"), "Network error: " + err.message, "error")
				$testBtn.prop("disabled", false).text("Test Connection")
			})
	})
})
